FastAPI runs `def` endpoints in a thread pool and `async def` endpoints on the event loop. Using `async def` with blocking code freezes the entire server.

```python
from fastapi import FastAPI
import time

app = FastAPI()

# WRONG — blocks the event loop
@app.get("/slow")
async def slow_endpoint():
    time.sleep(5)  # blocks ALL requests for 5 seconds!
    return {"status": "done"}

# CORRECT option 1: use def (runs in threadpool)
@app.get("/slow")
def slow_endpoint():
    time.sleep(5)  # runs in thread, doesn't block other requests
    return {"status": "done"}

# CORRECT option 2: use async with async operations
@app.get("/slow")
async def slow_endpoint():
    await asyncio.sleep(5)  # non-blocking
    return {"status": "done"}

# CORRECT option 3: run blocking code in executor
@app.get("/slow")
async def slow_endpoint():
    result = await asyncio.to_thread(time.sleep, 5)
    return {"status": "done"}
```

Rule of thumb: use `async def` only when you're calling `await` inside. Use plain `def` for CPU-bound or blocking I/O code.

Python automatically chains exceptions in except blocks, but you can accidentally lose the chain.

```python
# Automatic chaining — context preserved
try:
    int("abc")
except ValueError:
    raise RuntimeError("parse failed")
# RuntimeError has __context__ = ValueError

# Explicit chaining with 'from'
try:
    int("abc")
except ValueError as e:
    raise RuntimeError("parse failed") from e
# Shows: "The above exception was the direct cause..."

# Suppress chain with 'from None'
try:
    int("abc")
except ValueError:
    raise RuntimeError("parse failed") from None
# Only shows RuntimeError, no chain

# GOTCHA: re-raising a NEW exception in a nested try loses context
try:
    int("abc")
except ValueError:
    try:
        do_cleanup()
    except Exception:
        raise RuntimeError("cleanup failed")
        # Original ValueError lost! Use 'from e' to preserve it
```

Always use `from e` when you want explicit chaining, and `from None` when you intentionally want to hide the original exception.

Python's import system can handle some circular imports, but the module may be partially initialized, leading to `AttributeError` at runtime.

```python
# models.py
from services import UserService  # imports services.py

class User:
    def get_service(self):
        return UserService(self)

# services.py
from models import User  # circular! models.py not fully loaded yet

class UserService:
    def create(self) -> User:
        return User()
```

Fixes:
```python
# Fix 1: Import inside function (lazy import)
class UserService:
    def create(self):
        from models import User  # imported when called, not at module load
        return User()

# Fix 2: Use TYPE_CHECKING for type hints only
from __future__ import annotations
from typing import TYPE_CHECKING
if TYPE_CHECKING:
    from models import User

class UserService:
    def create(self) -> "User": ...  # string annotation, no runtime import

# Fix 3: Restructure into a shared module
```

The `from __future__ import annotations` (PEP 563) makes all annotations lazy strings, eliminating most circular import issues for type hints.

Module-scoped or session-scoped fixtures are created once and shared. If a test mutates the fixture's return value, subsequent tests see the mutation.

```python
import pytest

@pytest.fixture(scope="module")
def shared_list():
    return [1, 2, 3]

def test_append(shared_list):
    shared_list.append(4)
    assert shared_list == [1, 2, 3, 4]

def test_length(shared_list):
    # FAILS! shared_list is [1, 2, 3, 4] from previous test
    assert len(shared_list) == 3  # AssertionError: 4 != 3
```

Fix: use function scope (default) for mutable data, or return a copy/factory:

```python
@pytest.fixture
def fresh_list():  # scope="function" is default
    return [1, 2, 3]  # new list per test

# Or use a factory fixture
@pytest.fixture(scope="module")
def make_list():
    def _make():
        return [1, 2, 3]
    return _make
```

In Pydantic V2, field validators and model validators have specific execution orders that can lead to unexpected behavior.

```python
from pydantic import BaseModel, field_validator, model_validator

class Config(BaseModel):
    name: str = "default"
    items: list[str] = []

    @field_validator('name')
    @classmethod
    def validate_name(cls, v):
        # v is the actual value, never None for required fields
        return v.upper()

    @model_validator(mode='before')
    def check_data(cls, data):
        # data is the raw input dict — defaults NOT applied yet
        print(data)  # may not contain 'name' or 'items'
        return data

    @model_validator(mode='after')
    def check_model(self):
        # self is the fully constructed model — defaults ARE applied
        print(self.name)  # always has a value
        return self

# Gotcha:
Config()  # mode='before' sees {}, mode='after' sees name='DEFAULT', items=[]
```

Use `mode='before'` when you need to transform raw input, and `mode='after'` when you need access to the fully initialized model.

When using `@pytest.mark.parametrize`, duplicate parameter representations cause test ID collisions, which can make pytest skip or overwrite tests.

```python
import pytest

# Gotcha: complex objects get the same repr
@pytest.mark.parametrize("data", [
    {"a": 1, "b": 2},
    {"a": 3, "b": 4},
])  # IDs: test[data0], test[data1] — OK but not descriptive

# Better: use explicit IDs
@pytest.mark.parametrize("data", [
    pytest.param({"a": 1}, id="small"),
    pytest.param({"a": 100}, id="large"),
])
def test_process(data):
    ...

# Multiple parametrize decorators create cartesian product
@pytest.mark.parametrize("x", [1, 2])
@pytest.mark.parametrize("y", [3, 4])
def test_add(x, y):  # runs 4 times: (1,3), (1,4), (2,3), (2,4)
    assert x + y > 0
```

FastAPI returns 422 (not 400) when request validation fails. This confuses API consumers who expect 400 Bad Request.

```python
from fastapi import FastAPI, Body
from pydantic import BaseModel

app = FastAPI()

class Item(BaseModel):
    name: str
    price: float

@app.post("/items")
async def create(item: Item):
    return item

# POST /items with {} -> 422 Unprocessable Entity
# {
#   "detail": [
#     {"loc": ["body", "name"], "msg": "Field required", "type": "missing"},
#     {"loc": ["body", "price"], "msg": "Field required", "type": "missing"}
#   ]
# }

# To return 400 instead, add an exception handler:
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse

@app.exception_handler(RequestValidationError)
async def validation_handler(request, exc):
    return JSONResponse(
        status_code=400,
        content={"error": "Invalid request", "details": exc.errors()}
    )
```

The 422 status code is technically correct per the HTTP spec (RFC 4918) but many APIs prefer 400 for consistency.

Use `Protocol` (structural typing) instead of ABC for interfaces. This supports duck typing while maintaining type safety.

```python
from typing import Protocol, runtime_checkable

@runtime_checkable
class Repository(Protocol):
    async def get(self, id: str) -> dict | None: ...
    async def save(self, id: str, data: dict) -> None: ...

# Implementations don't need to inherit — just match the protocol
class PostgresRepo:
    def __init__(self, pool):
        self.pool = pool

    async def get(self, id: str) -> dict | None:
        async with self.pool.acquire() as conn:
            row = await conn.fetchrow("SELECT * FROM items WHERE id=$1", id)
            return dict(row) if row else None

    async def save(self, id: str, data: dict) -> None:
        async with self.pool.acquire() as conn:
            await conn.execute(
                "INSERT INTO items (id, data) VALUES ($1, $2)",
                id, json.dumps(data)
            )

class InMemoryRepo:
    def __init__(self):
        self.store: dict[str, dict] = {}

    async def get(self, id: str) -> dict | None:
        return self.store.get(id)

    async def save(self, id: str, data: dict) -> None:
        self.store[id] = data

# Service depends on protocol, not implementation
class ItemService:
    def __init__(self, repo: Repository):
        self.repo = repo

# Use InMemoryRepo in tests, PostgresRepo in production
assert isinstance(InMemoryRepo(), Repository)  # True at runtime
```

Chain generators to process large datasets without loading everything into memory. Each stage yields one item at a time.

```python
from pathlib import Path
from typing import Generator, Iterator
import csv

def read_csv_rows(path: Path) -> Generator[dict, None, None]:
    with path.open(encoding="utf-8") as f:
        reader = csv.DictReader(f)
        yield from reader  # yields one row at a time

def filter_active(rows: Iterator[dict]) -> Generator[dict, None, None]:
    for row in rows:
        if row["status"] == "active":
            yield row

def transform(rows: Iterator[dict]) -> Generator[dict, None, None]:
    for row in rows:
        yield {
            "name": row["name"].strip().title(),
            "email": row["email"].lower(),
            "score": float(row["score"]),
        }

def batch(items: Iterator, size: int = 1000) -> Generator[list, None, None]:
    batch = []
    for item in items:
        batch.append(item)
        if len(batch) >= size:
            yield batch
            batch = []
    if batch:
        yield batch

# Pipeline — processes millions of rows with constant memory
rows = read_csv_rows(Path("huge_file.csv"))
active = filter_active(rows)
transformed = transform(active)
for chunk in batch(transformed, size=500):
    db.bulk_insert(chunk)
```

Memory usage is O(batch_size) regardless of file size. Each generator only holds one item in memory at a time.

Combine structural pattern matching with guard clauses for clean, readable routing logic that replaces complex if/elif chains.

```python
from dataclasses import dataclass

@dataclass
class Request:
    method: str
    path: str
    body: dict | None = None
    user_role: str = "guest"

def handle_request(req: Request) -> dict:
    match req:
        case Request(method="GET", path="/health"):
            return {"status": "ok"}

        case Request(method="GET", path=p) if p.startswith("/api/users/"):
            user_id = p.split("/")[-1]
            return {"user_id": user_id}

        case Request(method="POST", path="/api/admin", user_role=role) if role != "admin":
            return {"error": "forbidden"}

        case Request(method="POST", path="/api/admin", body=body) if body:
            return {"created": body}

        case Request(method=method, path=path):
            return {"error": f"{method} {path} not found"}

# Match with nested structures
event = {"type": "click", "target": {"id": "submit-btn", "class": "primary"}}

match event:
    case {"type": "click", "target": {"id": str(element_id)}}:
        print(f"Clicked: {element_id}")
    case {"type": "keypress", "key": "Enter"}:
        print("Enter pressed")
```

Python's `functools.lru_cache` works for sync code, but async and TTL-based caching need different approaches.

```python
from functools import lru_cache, cache
import time
import asyncio

# Simple memoization (3.9+)
@cache  # same as lru_cache(maxsize=None)
def fibonacci(n: int) -> int:
    if n < 2:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

# LRU cache with size limit
@lru_cache(maxsize=128)
def get_config(key: str) -> dict:
    return load_from_disk(key)

# TTL cache using cachetools
from cachetools import TTLCache, cached

_cache = TTLCache(maxsize=100, ttl=300)  # 5 minute TTL

@cached(cache=_cache)
def get_user(user_id: int) -> dict:
    return db.query(f"SELECT * FROM users WHERE id={user_id}")

# Async TTL cache
class AsyncTTLCache:
    def __init__(self, ttl: float = 300):
        self._cache: dict[str, tuple[float, any]] = {}
        self._ttl = ttl

    def get(self, key: str):
        if key in self._cache:
            ts, value = self._cache[key]
            if time.monotonic() - ts < self._ttl:
                return value
            del self._cache[key]
        return None

    def set(self, key: str, value):
        self._cache[key] = (time.monotonic(), value)

cache = AsyncTTLCache(ttl=60)

async def get_data(key: str) -> dict:
    if (cached := cache.get(key)) is not None:
        return cached
    result = await fetch_from_api(key)
    cache.set(key, result)
    return result
```

TypeGuard (3.10+) and TypeIs (3.12+) help type checkers understand custom type-narrowing functions.

```python
from typing import TypeGuard, TypeIs  # TypeIs is 3.12+

# TypeGuard narrows the type in the positive branch
def is_string_list(val: list[object]) -> TypeGuard[list[str]]:
    return all(isinstance(x, str) for x in val)

def process(data: list[object]):
    if is_string_list(data):
        # type checker knows: data is list[str]
        print(data[0].upper())
    else:
        # type checker still sees: list[object]
        pass

# TypeIs (3.12+) — narrows in BOTH branches
def is_int(val: int | str) -> TypeIs[int]:
    return isinstance(val, int)

def handle(x: int | str):
    if is_int(x):
        print(x + 1)    # x is int
    else:
        print(x.upper())  # x is str (narrowed in negative branch!)

# TypeGuard would NOT narrow the else branch
def is_int_guard(val: int | str) -> TypeGuard[int]:
    return isinstance(val, int)

def handle2(x: int | str):
    if is_int_guard(x):
        print(x + 1)    # x is int
    else:
        print(x.upper())  # x is still int | str (not narrowed!)
```

Use `TypeIs` when your check is a true type narrowing (input and output types are related). Use `TypeGuard` when the narrowed type might not be a subtype.

A complete dataclass setup with custom validation, JSON round-tripping, and optional fields.

```python
from dataclasses import dataclass, field, asdict
from datetime import datetime
from typing import Self
import json

@dataclass(slots=True, frozen=True)
class Event:
    name: str
    timestamp: datetime
    tags: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    id: str = field(default_factory=lambda: str(uuid.uuid4()))

    def __post_init__(self):
        if not self.name:
            raise ValueError("name cannot be empty")
        if len(self.tags) > 10:
            raise ValueError("max 10 tags")

    def to_json(self) -> str:
        d = asdict(self)
        d["timestamp"] = self.timestamp.isoformat()
        return json.dumps(d)

    @classmethod
    def from_json(cls, data: str) -> Self:
        d = json.loads(data)
        d["timestamp"] = datetime.fromisoformat(d["timestamp"])
        return cls(**d)

    @classmethod
    def create(cls, name: str, **kwargs) -> Self:
        return cls(name=name, timestamp=datetime.now(), **kwargs)

# Usage
event = Event.create("deploy", tags=["production", "v2.1"])
json_str = event.to_json()
restored = Event.from_json(json_str)
assert event == restored
```

Complete logging setup with JSON formatting, file rotation, and separate handlers for different log levels.

```python
import logging
import logging.config

LOGGING_CONFIG = {
    "version": 1,
    "disable_existing_loggers": False,
    "formatters": {
        "standard": {
            "format": "%(asctime)s [%(levelname)s] %(name)s: %(message)s"
        },
        "json": {
            "()": "pythonjsonlogger.jsonlogger.JsonFormatter",
            "format": "%(asctime)s %(levelname)s %(name)s %(message)s",
        },
    },
    "handlers": {
        "console": {
            "class": "logging.StreamHandler",
            "level": "DEBUG",
            "formatter": "standard",
            "stream": "ext://sys.stdout",
        },
        "file": {
            "class": "logging.handlers.RotatingFileHandler",
            "level": "INFO",
            "formatter": "json",
            "filename": "app.log",
            "maxBytes": 10_000_000,  # 10MB
            "backupCount": 5,
        },
        "error_file": {
            "class": "logging.handlers.RotatingFileHandler",
            "level": "ERROR",
            "formatter": "json",
            "filename": "error.log",
            "maxBytes": 10_000_000,
            "backupCount": 10,
        },
    },
    "loggers": {
        "": {  # root logger
            "handlers": ["console", "file", "error_file"],
            "level": "INFO",
        },
        "uvicorn": {"level": "WARNING"},
        "sqlalchemy.engine": {"level": "WARNING"},
    },
}

logging.config.dictConfig(LOGGING_CONFIG)
logger = logging.getLogger(__name__)

logger.info("Application started", extra={"version": "2.0"})
```

Advanced pytest parametrize patterns for testing edge cases, error conditions, and complex scenarios.

```python
import pytest
from decimal import Decimal

# Parametrize with expected exceptions
@pytest.mark.parametrize("input_val,expected", [
    ("10.5", Decimal("10.5")),
    ("0", Decimal("0")),
    ("-3.14", Decimal("-3.14")),
    pytest.param("abc", None, marks=pytest.mark.xfail(raises=ValueError)),
    pytest.param("", None, marks=pytest.mark.xfail(raises=ValueError)),
])
def test_parse_decimal(input_val, expected):
    result = parse_decimal(input_val)
    assert result == expected

# Parametrize with IDs and indirect fixtures
@pytest.fixture
def api_client(request):
    """Create client with specified auth level."""
    auth = request.param
    return TestClient(app, headers={"Authorization": f"Bearer {auth}"})

@pytest.mark.parametrize("api_client,expected_status", [
    pytest.param("admin-token", 200, id="admin-can-access"),
    pytest.param("user-token", 403, id="user-forbidden"),
    pytest.param("invalid", 401, id="invalid-unauthorized"),
], indirect=["api_client"])
async def test_admin_endpoint(api_client, expected_status):
    resp = await api_client.get("/admin")
    assert resp.status_code == expected_status

# Parametrize class for shared test data
@pytest.mark.parametrize("x,y,expected", [
    (0, 0, 0), (1, 1, 2), (-1, 1, 0), (100, -100, 0),
])
class TestAddition:
    def test_add(self, x, y, expected):
        assert add(x, y) == expected

    def test_commutative(self, x, y, expected):
        assert add(y, x) == expected
```

Building a CLI tool with Click that supports async operations, environment config, and proper error handling.

```python
import click
import asyncio
from functools import wraps

# Async support for Click
def async_command(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        return asyncio.run(f(*args, **kwargs))
    return wrapper

@click.group()
@click.option("--verbose", "-v", is_flag=True)
@click.pass_context
def cli(ctx, verbose):
    ctx.ensure_object(dict)
    ctx.obj["verbose"] = verbose

@cli.command()
@click.argument("url")
@click.option("--output", "-o", type=click.Path(), default="output.json")
@click.option("--timeout", type=float, default=30.0)
@click.pass_context
@async_command
async def fetch(ctx, url, output, timeout):
    """Fetch data from URL and save to file."""
    if ctx.obj["verbose"]:
        click.echo(f"Fetching {url}...")

    try:
        import httpx
        async with httpx.AsyncClient() as client:
            resp = await client.get(url, timeout=timeout)
            resp.raise_for_status()

        with open(output, "w") as f:
            f.write(resp.text)

        click.secho(f"Saved to {output}", fg="green")
    except httpx.HTTPError as e:
        click.secho(f"Error: {e}", fg="red", err=True)
        raise SystemExit(1)

@cli.command()
@click.confirmation_option(prompt="Are you sure you want to reset?")
def reset():
    """Reset all data."""
    click.echo("Reset complete.")

if __name__ == "__main__":
    cli()
```

Usage: `python cli.py -v fetch https://api.example.com -o data.json`

Quick reference for Python 3.12+ type annotation syntax, covering the most common patterns.

```python
from typing import Self, Never, TypeGuard, override
from collections.abc import Callable, Sequence, Mapping, AsyncIterator

# New 3.12 syntax for generics
def first[T](items: Sequence[T]) -> T:
    return items[0]

# New 3.12 syntax for type aliases
type JSON = dict[str, 'JSON'] | list['JSON'] | str | int | float | bool | None
type Handler[T] = Callable[[T], None]
type Result[T, E] = T | E

# Bounded type variables
def max_value[T: (int, float)](a: T, b: T) -> T:
    return a if a > b else b

# Class with generic
class Stack[T]:
    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        self._items.append(item)

    def pop(self) -> T:
        return self._items.pop()

# Self type for fluent interfaces
class Builder:
    def set_name(self, name: str) -> Self:
        self.name = name
        return self

# Override decorator (3.12+)
class Child(Parent):
    @override
    def method(self) -> None:  # type checker ensures Parent has this method
        ...

# Never type for functions that don't return
def fatal_error(msg: str) -> Never:
    raise SystemExit(msg)

# Unpack for variadic generics
from typing import Unpack, TypedDict

class Options(TypedDict, total=False):
    timeout: float
    retries: int

def request(url: str, **kwargs: Unpack[Options]) -> None: ...
```
